   {2 - x} &amp; 3 &amp; {5x - 1}  \cr 

 } } \right| + \left| {\matrix{
   {x + 1} &amp; {2x} &amp; 3  \cr 
   {2x + 3} &amp; {x + 1} &amp; 1  \cr 
   {2 - x} &amp; {3x + 4} &amp; 5  \cr 

 } } \right|$$<br><br>$$ \Rightarrow \Delta '(0) = c = \left| {\matrix{
   1 &amp; 0 &amp; 0  \cr 
   2 &amp; 1 &amp; 0  \cr 
   { - 1} &amp; 4 &amp; { - 1}  \cr 

 } } \right| + \left| {\matrix{
